"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[2630],{17175(n,e,r){r.r(e),r.d(e,{assets:()=>d,contentTitle:()=>a,default:()=>p,frontMatter:()=>s,metadata:()=>t,toc:()=>c});const t=JSON.parse('{"id":"cpp14/make-unique","title":"std::make_unique","description":"C++14 std::make_unique \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp14/06-make-unique.md","sourceDirName":"cpp14","slug":"/cpp14/06-make-unique","permalink":"/LearnModernCpp/docs/cpp14/06-make-unique","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp14","permalink":"/LearnModernCpp/docs/tags/cpp-14"},{"inline":true,"label":"make_unique","permalink":"/LearnModernCpp/docs/tags/make-unique"}],"version":"current","sidebarPosition":7,"frontMatter":{"sidebar_position":7,"slug":"06-make-unique","title":"std::make_unique","description":"C++14 std::make_unique \u6559\u5b66\u793a\u4f8b","tags":["cpp14","make_unique"]},"sidebar":"docs","previous":{"title":"\u653e\u677e\u7684constexpr","permalink":"/LearnModernCpp/docs/cpp14/05-relaxed-constexpr"},"next":{"title":"[[deprecated]]\u5c5e\u6027","permalink":"/LearnModernCpp/docs/cpp14/07-deprecated-attribute"}}');var u=r(74848),i=r(28453);const s={sidebar_position:7,slug:"06-make-unique",title:"std::make_unique",description:"C++14 std::make_unique \u6559\u5b66\u793a\u4f8b",tags:["cpp14","make_unique"]},a="std::make_unique",d={},c=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function o(n){const e={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,i.R)(),...n.components};return(0,u.jsxs)(u.Fragment,{children:[(0,u.jsx)(e.header,{children:(0,u.jsx)(e.h1,{id:"stdmake_unique",children:"std::make_unique"})}),"\n",(0,u.jsx)(e.p,{children:"C++14 \u6807\u51c6\u5f15\u5165\u7684 std::make_unique \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,u.jsx)(e.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,u.jsx)(e.pre,{children:(0,u.jsx)(e.code,{className:"language-cpp",metastring:'title="cpp14/06_make_unique.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::make_unique\r\n * \u6240\u5c5e\u6807\u51c6: C++14\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::make_unique\u662f\u521b\u5efastd::unique_ptr\u7684\u5de5\u5382\u51fd\u6570\uff0c\r\n *          \u7c7b\u4f3c\u4e8eC++11\u4e2d\u5df2\u6709\u7684std::make_shared\u3002\u5b83\u5c01\u88c5\u4e86new\u64cd\u4f5c\uff0c\r\n *          \u76f4\u63a5\u6784\u9020\u5e76\u8fd4\u56de\u4e00\u4e2aunique_ptr\u5bf9\u8c61\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++11\u5f15\u5165\u4e86unique_ptr\u548cmake_shared\uff0c\u4f46\u9057\u6f0f\u4e86make_unique\u3002\r\n *              \u76f4\u63a5\u4f7f\u7528new\u5b58\u5728\u5f02\u5e38\u5b89\u5168\u95ee\u9898\uff08\u53c2\u6570\u6c42\u503c\u987a\u5e8f\u672a\u5b9a\u4e49\u65f6\u53ef\u80fd\u5185\u5b58\u6cc4\u6f0f\uff09\uff0c\r\n *              \u800c\u4e14new/delete\u7684\u663e\u5f0f\u4f7f\u7528\u4e0d\u7b26\u5408\u73b0\u4ee3C++\u7684\u8d44\u6e90\u7ba1\u7406\u7406\u5ff5\u3002\r\n *              make_unique\u586b\u8865\u4e86\u8fd9\u4e2a\u7a7a\u767d\uff0c\u4f7f"\u96f6new"\u7f16\u7a0b\u6210\u4e3a\u53ef\u80fd\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - make_unique<T>(args...) \u521b\u5efa\u5355\u4e2a\u5bf9\u8c61\u7684unique_ptr\r\n *   - make_unique<T[]>(n) \u521b\u5efa\u6570\u7ec4\u7c7b\u578b\u7684unique_ptr\r\n *   - \u6bd4\u76f4\u63a5new\u66f4\u5b89\u5168\uff08\u5f02\u5e38\u5b89\u5168\uff09\r\n *   - \u907f\u514d\u4ee3\u7801\u4e2d\u51fa\u73b0\u88f8new\uff0c\u7b26\u5408\u73b0\u4ee3C++\u6700\u4f73\u5b9e\u8df5\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <memory>\r\n#include <string>\r\n#include <vector>\r\n#include <utility>\r\n\r\n// \u8f85\u52a9\u7c7b\r\nclass Widget {\r\npublic:\r\n    Widget(int id, const std::string& name)\r\n        : id_(id), name_(name) {\r\n        std::cout << "    Widget(" << id_ << ", \\"" << name_ << "\\") \u6784\u9020\\n";\r\n    }\r\n\r\n    ~Widget() {\r\n        std::cout << "    Widget(" << id_ << ", \\"" << name_ << "\\") \u6790\u6784\\n";\r\n    }\r\n\r\n    void display() const {\r\n        std::cout << "    Widget[id=" << id_ << ", name=\\"" << name_ << "\\"]\\n";\r\n    }\r\n\r\n    int id() const { return id_; }\r\n\r\nprivate:\r\n    int id_;\r\n    std::string name_;\r\n};\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // 1. \u521b\u5efa\u5355\u4e2a\u5bf9\u8c61\r\n    std::cout << "  [\u521b\u5efa\u5355\u4e2a\u5bf9\u8c61]\\n";\r\n    auto p1 = std::make_unique<Widget>(1, "Alpha");\r\n    p1->display();\r\n\r\n    // 2. \u521b\u5efa\u57fa\u672c\u7c7b\u578b\r\n    auto p2 = std::make_unique<int>(42);\r\n    std::cout << "  make_unique<int>(42) = " << *p2 << "\\n";\r\n\r\n    auto p3 = std::make_unique<std::string>("Hello C++14");\r\n    std::cout << "  make_unique<string> = \\"" << *p3 << "\\"\\n";\r\n\r\n    // 3. \u521b\u5efa\u6570\u7ec4\r\n    std::cout << "\\n  [\u521b\u5efa\u6570\u7ec4]\\n";\r\n    auto arr = std::make_unique<int[]>(5);  // 5\u4e2aint\uff0c\u503c\u521d\u59cb\u5316\u4e3a0\r\n    for (int i = 0; i < 5; ++i) {\r\n        arr[i] = (i + 1) * 10;\r\n    }\r\n    std::cout << "  \u6570\u7ec4\u5185\u5bb9: ";\r\n    for (int i = 0; i < 5; ++i) {\r\n        std::cout << arr[i] << " ";\r\n    }\r\n    std::cout << "\\n";\r\n\r\n    // 4. \u4e0e\u624b\u52a8new\u7684\u5bf9\u6bd4\r\n    std::cout << "\\n  [\u4e0enew\u5bf9\u6bd4]\\n";\r\n\r\n    // \u65e7\u5199\u6cd5\uff08\u4e0d\u63a8\u8350\uff09\r\n    std::unique_ptr<Widget> old_way(new Widget(2, "OldWay"));\r\n\r\n    // \u65b0\u5199\u6cd5\uff08\u63a8\u8350\uff09\r\n    auto new_way = std::make_unique<Widget>(3, "NewWay");\r\n\r\n    std::cout << "  \u4e24\u79cd\u65b9\u5f0f\u529f\u80fd\u7b49\u4ef7\uff0c\u4f46make_unique\u66f4\u5b89\u5168\u66f4\u7b80\u6d01\\n";\r\n    std::cout << "\\n  --- \u4f5c\u7528\u57df\u7ed3\u675f\uff0c\u81ea\u52a8\u6790\u6784 ---\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// \u5f02\u5e38\u5b89\u5168\u95ee\u9898\u6f14\u793a\r\nint might_throw() {\r\n    // \u6a21\u62df\u53ef\u80fd\u629b\u51fa\u5f02\u5e38\u7684\u51fd\u6570\r\n    return 42;\r\n}\r\n\r\nvoid process(std::unique_ptr<Widget> w, int value) {\r\n    std::cout << "  \u5904\u7406Widget " << w->id() << " with value=" << value << "\\n";\r\n}\r\n\r\n// \u4f7f\u7528unique_ptr\u7684\u5de5\u5382\u6a21\u5f0f\r\nclass Shape {\r\npublic:\r\n    virtual ~Shape() = default;\r\n    virtual void draw() const = 0;\r\n    virtual std::string name() const = 0;\r\n};\r\n\r\nclass Circle : public Shape {\r\n    double radius_;\r\npublic:\r\n    explicit Circle(double r) : radius_(r) {}\r\n    void draw() const override {\r\n        std::cout << "    \u7ed8\u5236\u5706\u5f62 (\u534a\u5f84=" << radius_ << ")\\n";\r\n    }\r\n    std::string name() const override { return "Circle"; }\r\n};\r\n\r\nclass Rectangle : public Shape {\r\n    double w_, h_;\r\npublic:\r\n    Rectangle(double w, double h) : w_(w), h_(h) {}\r\n    void draw() const override {\r\n        std::cout << "    \u7ed8\u5236\u77e9\u5f62 (" << w_ << "x" << h_ << ")\\n";\r\n    }\r\n    std::string name() const override { return "Rectangle"; }\r\n};\r\n\r\n// \u5de5\u5382\u51fd\u6570\u8fd4\u56deunique_ptr\r\nstd::unique_ptr<Shape> create_shape(const std::string& type) {\r\n    if (type == "circle")\r\n        return std::make_unique<Circle>(5.0);\r\n    else if (type == "rectangle")\r\n        return std::make_unique<Rectangle>(3.0, 4.0);\r\n    return nullptr;\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // 1. \u5f02\u5e38\u5b89\u5168\u95ee\u9898\r\n    std::cout << "  [\u5f02\u5e38\u5b89\u5168]\\n";\r\n    // \u5371\u9669\u7684\u5199\u6cd5\uff08C++17\u4e4b\u524d\u53c2\u6570\u6c42\u503c\u987a\u5e8f\u672a\u5b9a\u4e49\uff09\uff1a\r\n    // process(std::unique_ptr<Widget>(new Widget(1, "Unsafe")), might_throw());\r\n    // \u5982\u679cnew\u6210\u529f\u4f46might_throw()\u5728unique_ptr\u6784\u9020\u524d\u629b\u51fa\u5f02\u5e38 -> \u5185\u5b58\u6cc4\u6f0f\uff01\r\n\r\n    // \u5b89\u5168\u7684\u5199\u6cd5\uff1a\r\n    process(std::make_unique<Widget>(1, "Safe"), might_throw());\r\n    // make_unique\u4fdd\u8bc1\uff1a\u8981\u4e48\u5b8c\u5168\u6210\u529f\uff0c\u8981\u4e48\u4e0d\u5206\u914d\u5185\u5b58\r\n\r\n    // 2. \u5de5\u5382\u6a21\u5f0f\r\n    std::cout << "\\n  [\u5de5\u5382\u6a21\u5f0f]\\n";\r\n    std::vector<std::unique_ptr<Shape>> shapes;\r\n    shapes.push_back(create_shape("circle"));\r\n    shapes.push_back(create_shape("rectangle"));\r\n    shapes.push_back(create_shape("circle"));\r\n\r\n    for (const auto& shape : shapes) {\r\n        if (shape) {\r\n            std::cout << "  " << shape->name() << " -> ";\r\n            shape->draw();\r\n        }\r\n    }\r\n\r\n    // 3. \u79fb\u52a8\u8bed\u4e49\u4e0emake_unique\r\n    std::cout << "\\n  [\u79fb\u52a8\u8bed\u4e49]\\n";\r\n    auto w1 = std::make_unique<Widget>(10, "Movable");\r\n    std::cout << "  w1 \u6709\u6548? " << (w1 ? "\u662f" : "\u5426") << "\\n";\r\n\r\n    auto w2 = std::move(w1);  // \u79fb\u52a8\u6240\u6709\u6743\r\n    std::cout << "  \u79fb\u52a8\u540e:\\n";\r\n    std::cout << "  w1 \u6709\u6548? " << (w1 ? "\u662f" : "\u5426") << "\\n";\r\n    std::cout << "  w2 \u6709\u6548? " << (w2 ? "\u662f" : "\u5426") << "\\n";\r\n    if (w2) w2->display();\r\n\r\n    // 4. \u5728\u5bb9\u5668\u4e2d\u4f7f\u7528\r\n    std::cout << "\\n  [\u5bb9\u5668\u4e2d\u4f7f\u7528]\\n";\r\n    std::vector<std::unique_ptr<Widget>> widgets;\r\n    for (int i = 0; i < 3; ++i) {\r\n        widgets.push_back(std::make_unique<Widget>(i, "Item" + std::to_string(i)));\r\n    }\r\n    std::cout << "  \u5bb9\u5668\u5305\u542b " << widgets.size() << " \u4e2aWidget\\n";\r\n    std::cout << "  --- \u6e05\u7a7a\u5bb9\u5668 ---\\n";\r\n    widgets.clear();  // \u81ea\u52a8\u6790\u6784\u6240\u6709Widget\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u96311\uff1amake_unique\u4e0d\u652f\u6301\u81ea\u5b9a\u4e49\u5220\u9664\u5668\r\n    std::cout << "  \u9677\u96311: make_unique\u4e0d\u652f\u6301\u81ea\u5b9a\u4e49\u5220\u9664\u5668\\n";\r\n    // \u9700\u8981\u81ea\u5b9a\u4e49\u5220\u9664\u5668\u65f6\uff0c\u53ea\u80fd\u7528\u6784\u9020\u51fd\u6570\r\n    auto custom_deleter = [](Widget* w) {\r\n        std::cout << "    [\u81ea\u5b9a\u4e49\u5220\u9664\u5668] ";\r\n        delete w;\r\n    };\r\n    std::unique_ptr<Widget, decltype(custom_deleter)>\r\n        p(new Widget(99, "CustomDel"), custom_deleter);\r\n    std::cout << "  \u9700\u8981\u81ea\u5b9a\u4e49\u5220\u9664\u5668\u65f6\uff0c\u53ea\u80fd\u7528 unique_ptr(new T, deleter)\\n";\r\n\r\n    // \u9677\u96312\uff1amake_unique<T[]>\u4e0d\u652f\u6301\u521d\u59cb\u5316\u5217\u8868\r\n    std::cout << "\\n  \u9677\u96312: make_unique<T[]>(n) \u53ea\u80fd\u503c\u521d\u59cb\u5316\uff08\u5f52\u96f6\uff09\\n";\r\n    auto arr = std::make_unique<int[]>(5);\r\n    std::cout << "    make_unique<int[]>(5) \u521d\u59cb\u503c: ";\r\n    for (int i = 0; i < 5; ++i) std::cout << arr[i] << " ";\r\n    std::cout << "(\u5168\u662f0)\\n";\r\n    // \u4e0d\u80fd\u5199 make_unique<int[]>({1,2,3,4,5})\r\n\r\n    // \u9677\u96313\uff1a\u4e0d\u8981\u7528make_unique\u521b\u5efa\u5df2\u6709\u5bf9\u8c61\u7684\u6307\u9488\r\n    std::cout << "\\n  \u9677\u96313: make_unique\u603b\u662f\u521b\u5efa\u65b0\u5bf9\u8c61\uff0c\u4e0d\u8981\u7528\u4e8e\u7ba1\u7406\u5df2\u6709\u6307\u9488\\n";\r\n    std::cout << "    int* raw = new int(42);\\n";\r\n    std::cout << "    auto up = std::make_unique<int>(42); // \u521b\u5efa\u65b0\u5bf9\u8c61\uff0c\u4e0d\u63a5\u7ba1raw\\n";\r\n    std::cout << "    // \u8981\u63a5\u7ba1\u5df2\u6709\u6307\u9488\uff0c\u7528: unique_ptr<int>(raw)\\n";\r\n\r\n    // \u9677\u96314\uff1amake_unique\u4f7f\u7528()\u521d\u59cb\u5316\uff0c\u4e0d\u662f{}\r\n    std::cout << "\\n  \u9677\u96314: make_unique\u4f7f\u7528\u5706\u62ec\u53f7\u521d\u59cb\u5316\\n";\r\n    // \u5bf9\u4e8e\u805a\u5408\u7c7b\u578b\uff0cC++14\u7684make_unique\u4e0d\u652f\u6301\u5217\u8868\u521d\u59cb\u5316\r\n    // struct Agg { int x; double y; };\r\n    // auto p = std::make_unique<Agg>(1, 2.0);  // C++14\u53ef\u80fd\u7f16\u8bd1\u5931\u8d25\uff08\u65e0\u6784\u9020\u51fd\u6570\uff09\r\n    // C++20\u7684make_unique\u624d\u652f\u6301\u805a\u5408\u521d\u59cb\u5316\r\n    std::cout << "    make_unique<T>(args...) \u4f7f\u7528T(args...)\u5f62\u5f0f\u521d\u59cb\u5316\\n";\r\n    std::cout << "    \u5bf9\u4e8e\u6ca1\u6709\u6784\u9020\u51fd\u6570\u7684\u805a\u5408\u7c7b\u578b\uff0cC++14\u4e2d\u53ef\u80fd\u4e0d\u652f\u6301\\n";\r\n\r\n    std::cout << "\\n  --- \u6790\u6784\u6f14\u793a ---\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::make_unique - C++14 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,u.jsx)(e.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,u.jsxs)(e.ul,{children:["\n",(0,u.jsx)(e.li,{children:(0,u.jsx)(e.a,{href:"https://en.cppreference.com/w/cpp/memory/unique_ptr/make_unique",children:"cppreference: std::make_unique"})}),"\n"]})]})}function p(n={}){const{wrapper:e}={...(0,i.R)(),...n.components};return e?(0,u.jsx)(e,{...n,children:(0,u.jsx)(o,{...n})}):o(n)}},28453(n,e,r){r.d(e,{R:()=>s,x:()=>a});var t=r(96540);const u={},i=t.createContext(u);function s(n){const e=t.useContext(i);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function a(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(u):n.components||u:s(n.components),t.createElement(i.Provider,{value:e},n.children)}}}]);